import { createMemoizedArray } from 'lodash';

function solve(nums, queries) {
    const n = nums.length;
    const maxK = 5;

    // Precompute popcount-depth for all possible values up to 1e15
    const popcountDepth = createMemoizedArray(1000000, (x) => {
        let depth = 0;
        let current = x;
        while (current > 0) {
            current = popcount(current);
            depth++;
            if (current === 1) break;
        }
        return depth;
    });

    // Create a 2D array to store the count of each popcount-depth in a range
    const freq = Array(n).fill(0).map(() => Array(maxK + 1).fill(0));

    // Initialize the frequency array
    for (let i = 0; i < n; i++) {
        const d = popcountDepth(nums[i]);
        if (d <= maxK) {
            freq[i][d] = 1;
        }
    }

    // Build prefix sums for each depth
    const prefix = Array(n).fill(0).map(() => Array(maxK + 1).fill(0));
    for (let i = 0; i < n; i++) {
        for (let k = 0; k <= maxK; k++) {
            prefix[i][k] = (i > 0 ? prefix[i - 1][k] : 0) + freq[i][k];
        }
    }

    const answer = [];

    for (const query of queries) {
        if (query[0] === 1) {
            const [l, r, k] = query.slice(1);
            let count = 0;
            for (let i = 0; i <= maxK; i++) {
                count += prefix[r][i] - (l > 0 ? prefix[l - 1][i] : 0);
            }
            answer.push(count);
        } else {
            const [idx, val] = query.slice(1);
            const oldVal = nums[idx];
            const newVal = val;
            nums[idx] = newVal;

            // Update the frequency array
            const oldD = popcountDepth(oldVal);
            if (oldD <= maxK) {
                freq[idx][oldD]--;
            }

            const newD = popcountDepth(newVal);
            if (newD <= maxK) {
                freq[idx][newD]++;
            }

            // Update the prefix sums
            for (let i = 0; i <= maxK; i++) {
                prefix[idx][i] = (idx > 0 ? prefix[idx - 1][i] : 0) + freq[idx][i];
            }
        }
    }

    return answer;
}

function popcount(x) {
    let count = 0;
    while (x) {
        x &= x - 1;
